from llama_index.core.postprocessor import SimilarityPostprocessor
from llama_index.core.schema import NodeWithScore

class JailbreakPostprocessor(SimilarityPostprocessor):
    def _postprocess_nodes(self, nodes: list[NodeWithScore], 
                          query_bundle, **kwargs):
        # Additional jailbreak checks
        for node in nodes:
            if any(keyword in node.node.text.lower() 
                   for keyword in ['ignore instructions', 'jailbreak', 'override']):
                nodes.remove(node)
        return super()._postprocess_nodes(nodes, query_bundle, **kwargs)

# Apply to query engine
query_engine = index.as_query_engine(
    node_postprocessors=[JailbreakPostprocessor(similarity_cutoff=0.7)]
)
