import { LlamaIndexAgent } from '@llamaindex/llama-index';

const ALLOWED_TOOLS = ['search_index', 'summarize_chunks'];

class SecureLlamaIndexAgent extends LlamaIndexAgent {
  async executeTool(toolName: string, input: any): Promise<any> {
    if (!ALLOWED_TOOLS.includes(toolName)) {
      throw new Error(`Tool ${toolName} not whitelisted`);
    }

    // Sanitize tool input
    const sanitizedInput = this.sanitizeInput(input);
    return await super.executeTool(toolName, sanitizedInput);
  }

  sanitizeInput(input: any): any {
    // Remove dangerous patterns from tool inputs
    if (typeof input === 'string') {
      return input.replace(/\b(delete|drop|exec|rm)\b/gi, '[BLOCKED]');
    }
    return input;
  }
}
